import React from "react";

const ContenedorLateral = ({
  subtitulo,
  texto,
  imagen,
  ancho,
  alto,
  ovaloRedondez,
  cuadroRedondez,
}) => {
  // Determinamos el tamaño del óvalo de acuerdo al ancho del contenedor (ancho)
  const ovaloAncho = `calc(${ancho} * 0.4)`; // 40% del ancho del contenedor para el óvalo
  const ovaloAlto = `calc(${alto} * 0.15)`;  // Aumentamos a 15% de la altura del contenedor para el óvalo

  return (
    <div
      className="relative mt-5 bg-black flex flex-col items-center justify-start z-10 shadow-2xl ml-auto"
      style={{
        width: ancho, // Usamos el prop para el ancho
        height: alto, // Usamos el prop para el alto
        borderRadius: cuadroRedondez, // Redondez dinámica para el contenedor
      }}
    >
      {/* Subtítulo en óvalo blanco */}
      <div
        className="absolute -top-5 bg-white text-black font-semibold shadow px-6 py-2 text-sm md:text-base lg:text-lg"
        style={{
          borderRadius: ovaloRedondez, // Redondez dinámica para el óvalo
          left: "50%", // Inicialmente centrado
          transform: "translateX(-50%)", // Centrado
          width: ovaloAncho, // Ancho del óvalo basado en el contenedor
          height: ovaloAlto, // Altura del óvalo basada en el contenedor
        }}
      >
        {subtitulo}
      </div>

      {/* Contenido dentro del contenedor */}
      <div className="mt-6 w-full text-white text-sm text-center space-y-6">
        {/* Agregamos margen superior al texto */}
        <p className="leading-relaxed text-xs sm:text-sm md:text-base lg:text-lg">
          {texto}
        </p>

        <div className="flex justify-center">
          <img
            src={imagen}
            alt="contenido dinámico"
            className="rounded-lg object-contain max-w-[90%] max-h-[30vh]"
          />
        </div>
      </div>
    </div>
  );
};

export default ContenedorLateral;
